#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <sys/wait.h>

void sigchld_handler(int sig);

int main() {
 pid_t pids[5];
 struct sigaction sa;

 // Setup signal handler
 sa.sa_handler = sigchld_handler;
 sa.sa_flags = SA_RESTART;
 sigemptyset(&sa.sa_mask);
 sigaction(SIGCHLD, &sa, NULL);

 // Fork 5 child processes
 for (int i = 0; i < 5; i++) {
 pids[i] = fork();
 if (pids[i] == 0) {
 // Child process
 printf("Child %d (PID %d) working...\n", i, getpid());
 sleep(i + 1); // Do some work
 printf("Child %d exiting with status %d\n", i, i*10);
 _exit(i * 10); // Exit with status
 } else if (pids[i] < 0) {
 perror("fork failed");
 exit(1);
 }
 }

 // Parent waits for all children
 printf("Parent waiting for children...\n");
 for (int i = 0; i < 5; i++) {
 int status;
 waitpid(pids[i], &status, 0);
 }
 printf("All children reaped.\n");
 return 0;
}

