 if (WIFEXITED(status)) {
 printf("Handler: Child %d exited with %d\n",
 pid, WEXITSTATUS(status));
 }
 }
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <sys/wait.h>

int main() {
 pid_t pid1, pid2;

 pid1 = fork();
 if (pid1 < 0) {
 perror("First fork failed");
 exit(1);
 }

 if (pid1 == 0) {
 // First child process
 pid2 = fork();
 if (pid2 < 0) {
 perror("Second fork failed");
 _exit(1);
 }

 if (pid2 == 0) {
 // Grandchild process (becomes orphan)
 // Do actual work here
 printf("Grandchild (PID %d) working...\n", getpid());
 sleep(2);
 printf("Grandchild finishing.\n");
 _exit(0);
 } else {
 // First child exits immediately
 printf("First child (PID %d) exiting.\n", getpid());
 _exit(0); // No waiting for grandchild
 }
 } else {
 // Original parent
 wait(NULL); // Wait for first child only
 printf("Parent: First child reaped.\n");
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <unistd.h>
#include <signal.h>
#include <sys/wait.h>

int main() {
 struct sigaction sa;

 // Set SA_NOCLDWAIT to prevent zombies
 sa.sa_handler = SIG_IGN; // Can also use custom handler
 sa.sa_flags = SA_NOCLDWAIT; // Children won't become zombies
 sigemptyset(&sa.sa_mask);
 sigaction(SIGCHLD, &sa, NULL);

 printf("Forking child with SA_NOCLDWAIT set...\n");

 pid_t pid = fork();
 if (pid == 0) {
 // Child
 printf("Child (PID %d) sleeping...\n", getpid());
 sleep(1);
 printf("Child exiting.\n");
 _exit(42);
 } else {
 // Parent - no wait() needed!
 sleep(2);
 printf("Parent: No zombie created due to SA_NOCLDWAIT.\n");
 printf("Child exit status is lost with SA_NOCLDWAIT.\n");
 }

 return 0;
}
